import { GoogleGenAI, Type } from "@google/genai";
import { Language } from "../types";

const API_KEY = process.env.API_KEY || "";

export const summarizeIncident = async (description: string, lang: Language) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Summarize the following incident report in a clear and concise way in ${lang}: ${description}`,
  });
  return response.text;
};

export const transcribeAudio = async (base64Audio: string, lang: Language) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      { inlineData: { mimeType: 'audio/pcm;rate=16000', data: base64Audio } },
      { text: `Transcribe this audio report accurately in ${lang}.` }
    ],
  });
  return response.text;
};

export const predictResourceAllocation = async (incidentsCount: number) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on ${incidentsCount} recent incidents in Addis Ababa, predict the required patrol resources (Vehicles, Officers, ETA) for the next 4 hours. Return in JSON format with an array of assignments.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            officer: { type: Type.STRING },
            vehicle: { type: Type.STRING },
            shift: { type: Type.STRING },
            zone: { type: Type.STRING },
            eta: { type: Type.STRING },
          },
          required: ["officer", "vehicle", "shift", "zone", "eta"]
        }
      }
    }
  });
  try {
    return JSON.parse(response.text || "[]");
  } catch {
    return [];
  }
};

export const buildLegalCase = async (incident: any) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Build a formal legal case structure for the following incident: ${JSON.stringify(incident)}. Include Evidence Summary, Witness List Placeholder, and Suggested Legal Charges based on Ethiopian law.`,
    config: {
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });
  return response.text;
};

export const translateText = async (text: string, targetLang: Language) => {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-lite-latest',
        contents: `Translate this text to ${targetLang}: ${text}`,
    });
    return response.text;
};

import React from 'react';
import { Language } from '../types';

interface LanguageToggleProps {
  current: Language;
  onSelect: (lang: Language) => void;
}

export const LanguageToggle: React.FC<LanguageToggleProps> = ({ current, onSelect }) => {
  const languages: Language[] = ['Oromo', 'Amharic', 'English'];

  return (
    <div className="flex bg-gray-100 p-1 rounded-lg">
      {languages.map((lang) => (
        <button
          key={lang}
          onClick={() => onSelect(lang)}
          className={`px-3 py-1 text-sm font-medium rounded-md transition-all ${
            current === lang
              ? 'bg-white text-blue-600 shadow-sm'
              : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          {lang}
        </button>
      ))}
    </div>
  );
};

import React, { useEffect, useRef } from 'react';

interface MapComponentProps {
  center?: [number, number];
  zoom?: number;
  markers?: Array<{ lat: number; lng: number; title: string }>;
  onClick?: (lat: number, lng: number) => void;
  interactive?: boolean;
}

export const MapComponent: React.FC<MapComponentProps> = ({
  center = [9.03, 38.74], // Addis Ababa
  zoom = 12,
  markers = [],
  onClick,
  interactive = true,
}) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    if (!mapInstanceRef.current) {
      // @ts-ignore
      mapInstanceRef.current = L.map(mapContainerRef.current).setView(center, zoom);
      // @ts-ignore
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapInstanceRef.current);
    }

    if (onClick && interactive) {
      mapInstanceRef.current.on('click', (e: any) => {
        onClick(e.latlng.lat, e.latlng.lng);
      });
    }

    // Update markers
    const markerGroup = (window as any).L.layerGroup().addTo(mapInstanceRef.current);
    markers.forEach(m => {
       // @ts-ignore
      L.marker([m.lat, m.lng]).addTo(markerGroup).bindPopup(m.title);
    });

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, [center, zoom, markers, onClick, interactive]);

  return <div ref={mapContainerRef} className="h-full w-full min-h-[300px] shadow-inner border border-gray-200" />;
};

