                     <td className="px-6 py-4">{i.citizenName}</td>
                     <td className="px-6 py-4">
                       <span className="bg-blue-50 text-blue-600 px-2 py-1 rounded-md text-[10px] font-bold">IMAGE_DATA</span>
                     </td>
                     <td className="px-6 py-4 space-x-2">
                       <button className="bg-green-500 text-white px-3 py-1 rounded-lg text-xs font-bold shadow-sm">Validate</button>
