    if (submitted) {
      return (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl shadow-sm border border-gray-100">
          <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
            <CheckCircle size={32} />
          </div>
          <h2 className="text-2xl font-bold text-gray-800">Report Submitted</h2>
          <p className="text-gray-500 mt-2">Thank you for helping keep our city safe.</p>
        </div>
      );
    }

    return (
      <div className="max-w-2xl mx-auto bg-white p-8 rounded-3xl shadow-sm border border-gray-100 space-y-6">
        <h2 className="text-2xl font-bold text-[#2A3F54]">{t('report_incident')}</h2>

        <div>
          <label className="block text-sm font-semibold mb-2 text-gray-700">Description</label>
          <textarea 
            value={desc}
            onChange={(e) => setDesc(e.target.value)}
            className="w-full h-32 p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
            placeholder="Tell us what happened..."
          />
          <button 
            onClick={handleAutoSummary}
            disabled={loading}
            className="mt-2 text-sm text-blue-600 font-medium hover:underline flex items-center gap-1"
          >
            {loading ? 'Analyzing...' : 'Auto-Generate Summary with AI ✨'}
          </button>
        </div>

        {summary && (
          <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100">
             <label className="text-xs font-bold text-blue-600 uppercase mb-1 block">AI Summary</label>
             <p className="text-sm text-blue-800 italic">{summary}</p>
          </div>
        )}

        <div className="grid md:grid-cols-2 gap-4">
           <div>
             <label className="block text-sm font-semibold mb-2 text-gray-700">{t('upload_evidence')}</label>
             <input type="file" className="text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100" />
           </div>
           <div>
             <label className="block text-sm font-semibold mb-2 text-gray-700">Location</label>
             <div className="h-40 rounded-2xl overflow-hidden border border-gray-200">
               <MapComponent zoom={14} />
             </div>
           </div>
        </div>

        <button onClick={handleSubmit} className="w-full bg-[#1ABC9C] text-white py-4 rounded-2xl font-bold shadow-lg hover:bg-[#16a085] transition-all">
          {t('submit')}
        </button>
      </div>
    );
  };

  const OfficerDashboard = () => {
    const [predicting, setPredicting] = useState(false);
    const [allocations, setAllocations] = useState<any[]>([]);

    const handlePredict = async () => {
      setPredicting(true);
      const res = await predictResourceAllocation(incidents.length);
      setAllocations(res);
      setPredicting(false);
    };

    if (currentPage === 'hotspots') {
      return (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-bold text-[#2A3F54]">{t('hotspot_map')}</h2>
            <button 
              onClick={handlePredict}
              className="bg-[#3498DB] text-white px-4 py-2 rounded-xl text-sm font-semibold shadow hover:bg-blue-600"
            >
              {predicting ? 'Processing AI Models...' : 'Predict Resource Needs ✨'}
            </button>
          </div>

          <div className="h-[500px] bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden">
            <MapComponent markers={incidents.map(i => ({ lat: i.location.lat, lng: i.location.lng, title: i.summary || i.id }))} />
          </div>

          <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
            <h3 className="text-lg font-bold mb-4">{t('predicted_resources')}</h3>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-gray-100 text-gray-500 text-sm">
                    <th className="pb-3 font-semibold">Officer</th>
                    <th className="pb-3 font-semibold">Vehicle</th>
                    <th className="pb-3 font-semibold">Shift</th>
                    <th className="pb-3 font-semibold">Zone</th>
                    <th className="pb-3 font-semibold">ETA</th>
                  </tr>
                </thead>
                <tbody className="text-sm">
                  {(allocations.length > 0 ? allocations : [
                    { officer: 'Tadesse K.', vehicle: 'SUV-22', shift: 'Day', zone: 'Sector A', eta: '10 mins' },
                    { officer: 'Mulugeta S.', vehicle: 'MOT-05', shift: 'Day', zone: 'Sector C', eta: '5 mins' }
                  ]).map((a, idx) => (
                    <tr key={idx} className="border-b border-gray-50 last:border-0">
                      <td className="py-4 font-medium">{a.officer}</td>
                      <td className="py-4">{a.vehicle}</td>
                      <td className="py-4">{a.shift}</td>
                      <td className="py-4">{a.zone}</td>
                      <td className="py-4 text-[#27AE60] font-bold">{a.eta}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      );
    }

    if (currentPage === 'report') {
      return (
        <div className="space-y-6">
           <div className="flex justify-between items-center">
             <h2 className="text-2xl font-bold text-[#2A3F54]">{t('report_incident')} - Investigation List</h2>
           </div>

           <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                 <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
                   <tr>
                     <th className="px-6 py-4">Incident</th>
                     <th className="px-6 py-4">Evidence</th>
                     <th className="px-6 py-4">Status</th>
                     <th className="px-6 py-4">Action</th>
                   </tr>
                 </thead>
                 <tbody className="text-sm">
                   {incidents.map(i => (
                     <tr key={i.id} className="border-b border-gray-50 last:border-0 hover:bg-gray-50 transition-colors">
                       <td className="px-6 py-4">
                         <p className="font-bold">{i.id}</p>
                         <p className="text-xs text-gray-500">{i.summary}</p>
                       </td>
                       <td className="px-6 py-4">
                         <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center text-gray-400">
                           {i.evidenceType === 'image' ? <Users size={20} /> : <FileText size={20} />}
                         </div>
                       </td>
                       <td className="px-6 py-4">
                         <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                           i.status === 'Pending' ? 'bg-yellow-100 text-yellow-700' :
                           i.status === 'Critical' ? 'bg-red-100 text-red-700' :
                           'bg-green-100 text-green-700'
                         }`}>{i.status}</span>
                       </td>
                       <td className="px-6 py-4">
                         <button 
                           onClick={() => handleBuildCase(i)}
                           className="flex items-center gap-2 bg-[#2A3F54] text-white px-3 py-1.5 rounded-lg text-xs font-bold shadow-sm hover:bg-[#1f2d3c]"
                         >
                           <Gavel size={14} /> Build Case
                         </button>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
           </div>

           {selectedIncidentForCase && (
             <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
               <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[80vh] overflow-hidden flex flex-col shadow-2xl">
                 <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-[#2A3F54] text-white">
                   <h3 className="text-lg font-bold">AI Case Builder: {selectedIncidentForCase.id}</h3>
                   <button onClick={() => setSelectedIncidentForCase(null)} className="p-1 hover:bg-white/10 rounded-full">
                     <X size={20} />
                   </button>
                 </div>
                 <div className="p-6 overflow-y-auto flex-1 bg-gray-50">
                    {isCaseLoading ? (
                      <div className="flex flex-col items-center justify-center py-12 space-y-4">
                        <div className="w-8 h-8 border-4 border-[#1ABC9C] border-t-transparent rounded-full animate-spin"></div>
                        <p className="text-sm text-gray-500 font-medium">Gemini AI is analyzing evidence & local statutes...</p>
                      </div>
                    ) : (
                      <div className="prose prose-sm max-w-none">
                         <pre className="whitespace-pre-wrap font-sans text-gray-700 leading-relaxed">
                           {aiCaseText}
                         </pre>
                      </div>
                    )}
                 </div>
                 <div className="p-4 border-t border-gray-100 flex justify-end gap-3 bg-white">
                   <button onClick={() => setSelectedIncidentForCase(null)} className="px-4 py-2 text-sm font-bold text-gray-500 hover:bg-gray-100 rounded-xl">Close</button>
                   <button className="px-4 py-2 text-sm font-bold bg-[#1ABC9C] text-white rounded-xl shadow-lg">Export Legal Draft</button>
                 </div>
               </div>
             </div>
           )}
        </div>
      );
    }

    if (currentPage === 'voice') {
      const [transcription, setTranscription] = useState('');
      const [recording, setRecording] = useState(false);

      const startRecording = () => {
        setRecording(true);
        setTimeout(async () => {
          setRecording(false);
          setTranscription("Reporting from Mercato market. Suspicious activity noticed near the main entrance. Two individuals appearing to scout shop security systems. No immediate threat but requesting additional foot patrol.");
        }, 3000);
      };

      return (
        <div className="max-w-2xl mx-auto space-y-6">
          <h2 className="text-2xl font-bold text-[#2A3F54]">{t('voice_report')}</h2>
          <div className="bg-white p-10 rounded-3xl shadow-sm border border-gray-100 flex flex-col items-center">
             <div className={`p-8 rounded-full mb-6 transition-all ${recording ? 'bg-red-100 animate-pulse' : 'bg-gray-100'}`}>
               <Mic size={48} className={recording ? 'text-red-500' : 'text-gray-400'} />
             </div>
             <button onClick={startRecording} className={`px-8 py-3 rounded-full font-bold transition-all ${recording ? 'bg-red-500 text-white' : 'bg-[#1ABC9C] text-white shadow-lg'}`}>
               {recording ? 'Recording...' : 'Start Voice Report'}
             </button>
             <p className="mt-4 text-xs text-gray-500">Press to speak. Gemini AI will transcribe your field report.</p>
          </div>

          {transcription && (
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 space-y-4">
              <label className="text-xs font-bold text-gray-400 uppercase">Transcribed Report</label>
              <textarea 
                value={transcription}
                readOnly
                className="w-full h-40 p-4 bg-gray-50 rounded-2xl text-gray-700 italic border-none focus:ring-0"
              />
              <button className="w-full bg-[#2A3F54] text-white py-3 rounded-xl font-bold hover:bg-[#1f2d3c]">File Report</button>
            </div>
          )}
        </div>
      );
    }

    return null;
  };

  const AdminDashboard = () => {
    const chartData = [
      { name: 'Mon', incidents: 40, res: 24 },
      { name: 'Tue', incidents: 30, res: 13 },
      { name: 'Wed', incidents: 20, res: 38 },
      { name: 'Thu', incidents: 27, res: 39 },
      { name: 'Fri', incidents: 18, res: 48 },
      { name: 'Sat', incidents: 23, res: 38 },
      { name: 'Sun', incidents: 34, res: 43 },
    ];

    if (currentPage === 'kpi') {
      return (
        <div className="space-y-6">
          <h2 className="text-2xl font-bold text-[#2A3F54]">{t('kpi_overview')}</h2>
          <div className="grid md:grid-cols-4 gap-4">
            {[
              { label: 'Active Patrols', value: '42', color: 'text-blue-600' },
              { label: 'Pending Reports', value: incidents.filter(i=>i.status === 'Pending').length.toString(), color: 'text-yellow-600' },
              { label: 'Validated Cases', value: '156', color: 'text-green-600' },
              { label: 'Critical Zones', value: '3', color: 'text-red-600' },
            ].map(stat => (
              <div key={stat.label} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                <p className="text-xs font-bold text-gray-500 uppercase">{stat.label}</p>
                <p className={`text-3xl font-black mt-1 ${stat.color}`}>{stat.value}</p>
              </div>
            ))}
          </div>

          <div className="grid md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold mb-6">Incident Trends (Weekly)</h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} />
                    <YAxis axisLine={false} tickLine={false} />
                    <Tooltip />
                    <Line type="monotone" dataKey="incidents" stroke="#3498DB" strokeWidth={3} dot={{ r: 4 }} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold mb-6">Officer Performance</h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} />
                    <YAxis axisLine={false} tickLine={false} />
                    <Tooltip />
                    <Bar dataKey="res" fill="#1ABC9C" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      );
    }

    if (currentPage === 'validation') {
      return (
        <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
           <div className="p-6 border-b border-gray-100">
             <h2 className="text-xl font-bold">{t('validation')} - Pending Incidents</h2>
           </div>
           <div className="overflow-x-auto">
             <table className="w-full text-left">
               <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase">
                 <tr>
                   <th className="px-6 py-4">ID</th>
                   <th className="px-6 py-4">Citizen</th>
                   <th className="px-6 py-4">Status</th>
                   <th className="px-6 py-4">Action</th>
                 </tr>
               </thead>
               <tbody className="text-sm">
                 {incidents.map(i => (
                   <tr key={i.id} className="border-b border-gray-50 last:border-0 hover:bg-gray-50 transition-colors">
                     <td className="px-6 py-4">
                       <span className="font-bold">{i.id}</span>
                       <p className="text-xs text-gray-400">{i.summary}</p>
                     </td>
                     <td className="px-6 py-4">{i.citizenName}</td>
                     <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                          i.status === 'Pending' ? 'bg-yellow-100 text-yellow-700' :
                          i.status === 'Critical' ? 'bg-red-100 text-red-700' :
                          'bg-green-100 text-green-700'
                        }`}>{i.status}</span>
                     </td>
                     <td className="px-6 py-4 space-x-2">
                       {i.status === 'Pending' && (
                         <button 
                           onClick={() => updateIncidentStatus(i.id, 'Validated')}
                           className="bg-green-500 text-white px-3 py-1 rounded-lg text-xs font-bold shadow-sm"
                         >
                           Validate
                         </button>
                       )}
                       <button onClick={() => updateIncidentStatus(i.id, 'Resolved')} className="bg-gray-100 text-gray-600 px-3 py-1 rounded-lg text-xs font-bold">Dismiss</button>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
           </div>
        </div>
      );
    }

    if (currentPage === 'planning') {
       return (
         <div className="space-y-6">
            <h2 className="text-2xl font-bold text-[#2A3F54]">{t('resource_planning')}</h2>
            <div className="grid lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 h-[500px] bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden relative">
                 <div className="absolute top-4 right-4 z-[1000] bg-white p-3 rounded-xl shadow-lg border border-gray-100">
                    <p className="text-[10px] font-bold text-gray-400 uppercase">Predictive Hotspot Heatmap</p>
                    <div className="flex items-center gap-2 mt-1">
                       <div className="w-3 h-3 rounded-full bg-red-500"></div>
                       <span className="text-xs font-medium">High Probability</span>
                    </div>
                 </div>
                 <MapComponent markers={incidents.map(i => ({ lat: i.location.lat + 0.01, lng: i.location.lng - 0.01, title: 'Predicted Hotspot' }))} />
              </div>
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                 <h3 className="font-bold mb-4">Patrol Schedule</h3>
                 <div className="space-y-4">
                    {[
                      { officer: 'Inspector Solomon', zone: 'Sector A', time: '08:00 - 16:00' },
                      { officer: 'Officer Meron', zone: 'Sector D', time: '10:00 - 18:00' },
                      { officer: 'Officer Dawit', zone: 'Sector C', time: '14:00 - 22:00' },
                    ].map((p, i) => (
                      <div key={i} className="p-3 bg-gray-50 rounded-xl border border-gray-100">
                         <p className="text-sm font-bold text-[#2A3F54]">{p.officer}</p>
                         <div className="flex justify-between mt-1 text-xs text-gray-500">
                            <span>{p.zone}</span>
                            <span className="font-medium">{p.time}</span>
                         </div>
                      </div>
                    ))}
                 </div>
                 <button className="w-full mt-6 border-2 border-[#1ABC9C] text-[#1ABC9C] py-3 rounded-xl font-bold hover:bg-blue-50 transition-colors">
                    Optimize with AI
                 </button>
              </div>
            </div>
         </div>
       );
    }

    return null;
  };

  const AlertsFeed = () => (
    <div className="max-w-3xl mx-auto space-y-4">
      <h2 className="text-2xl font-bold text-[#2A3F54] mb-6">{t('safety_alerts')}</h2>
      {alerts.map(alert => (
        <div key={alert.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex gap-4">
           <div className={`flex-shrink-0 w-12 h-12 rounded-2xl flex items-center justify-center ${alert.severity === 'high' ? 'bg-red-100 text-red-500' : 'bg-yellow-100 text-yellow-500'}`}>
             <AlertTriangle size={24} />
           </div>
           <div className="flex-1">
             <div className="flex justify-between items-center mb-1">
               <h3 className="font-bold text-lg">{alert.title}</h3>
               <span className="text-xs text-gray-400">{alert.timestamp}</span>
             </div>
             <p className="text-gray-600">{alert.message}</p>
             <div className="mt-4 flex gap-2">
               <button className="text-xs font-bold text-blue-600 hover:underline">View on Map</button>
               <button className="text-xs font-bold text-gray-400 hover:underline">Share via SMS</button>
             </div>
           </div>
        </div>
      ))}
    </div>
  );

  const renderContent = () => {
    if (role === 'Citizen') {
      switch(currentPage) {
        case 'home': return <CitizenHome />;
        case 'report': return <ReportIncident />;
        case 'alerts': return <AlertsFeed />;
        default: return <CitizenHome />;
      }
    } else if (role === 'Officer') {
       return <OfficerDashboard />;
    } else if (role === 'Admin') {
       return <AdminDashboard />;
    }
  };

  return (
    <div className="min-h-screen bg-[#F7F9FC]">
      <Header />
      <Sidebar />
      <main className="lg:ml-64 p-4 md:p-8 pt-6">
        {renderContent()}
      </main>

      {/* Floating Action for Mobile Citizen */}
      {role === 'Citizen' && currentPage === 'home' && (
        <button 
          onClick={() => setCurrentPage('report')}
          className="fixed bottom-6 right-6 lg:hidden bg-[#1ABC9C] text-white p-4 rounded-full shadow-2xl z-40"
        >
          <FileText size={28} />
        </button>
      )}
    </div>
  );
};

export default App;

